const now=()=>Date.now();
const secureUnit=()=>crypto.randomInt(0,1000000000)/1000000000;
const round=n=>Math.round((Number(n)||0)*100)/100;
const clean=v=>String(v??'').trim();
const refCode=()=>crypto.randomBytes(4).toString('hex').toUpperCase();
const reference=p=>`${p}-${new Date().toISOString().slice(0,10).replace(/-/g,'')}-${crypto.randomBytes(4).toString('hex').toUpperCase()}`;
const maskEmail=v=>{v=clean(v);if(!v.includes('@'))return v;const [a,b]=v.split('@');return `${a.slice(0,2)}***${a.slice(-1)}@${b}`};
const maskName=v=>{v=clean(v)||'ADNOR User';return v.includes('@')?maskEmail(v):(v.length>4?`${v.slice(0,2)}***${v.slice(-1)}`:`${v.slice(0,1)}***`)};
const maskPhone=v=>{v=clean(v);return v.length>5?`${v.slice(0,3)}***${v.slice(-3)}`:v};
const keyify=v=>clean(v).toLowerCase().replace(/[.#$\[\]/]/g,'_');
const turkeyDay=(ts=now())=>new Intl.DateTimeFormat('en-CA',{timeZone:'Europe/Istanbul',year:'numeric',month:'2-digit',day:'2-digit'}).format(new Date(ts));
const turkeyMonth=(ts=now())=>turkeyDay(ts).slice(0,7);
const dayDiff=(a,b)=>Math.round((new Date(`${b}T12:00:00Z`)-new Date(`${a}T12:00:00Z`))/86400000);
const nextDrawTime=(type,ts)=>{const d=new Date(Number(ts));if(type==='daily')d.setUTCDate(d.getUTCDate()+1);else if(type==='weekly')d.setUTCDate(d.getUTCDate()+7);else if(type==='monthly')d.setUTCMonth(d.getUTCMonth()+1);else d.setUTCFullYear(d.getUTCFullYear()+1);return d.getTime()};

function requireAuth(req){if(!req.auth)throw new HttpsError('unauthenticated','Login required.');return req.auth.uid}
async function requireClaim(req,claim){const uid=requireAuth(req);if(!req.auth.token?.[claim])throw new HttpsError('permission-denied',`${claim} permission required.`);if(claim==='admin'){const role=await getVal(`admins/${uid}`);if(!role?.active)throw new HttpsError('permission-denied','Administrator access is inactive.')}if(claim==='agent'){const role=await getVal(`agents/${uid}`);if(!role||role.active===false)throw new HttpsError('permission-denied','Agent access is inactive.')}return uid}
function number(v,name,min=0,max=1e9){const n=Number(v);if(!Number.isFinite(n)||n<min||n>max)throw new HttpsError('invalid-argument',`${name} is invalid.`);return round(n)}
async function getVal(path){return (await db.ref(path).get()).val()}
async function audit(action,data={}){const id=db.ref('audit').push().key;await db.ref(`audit/${id}`).set({action,...data,createdAt:admin.database.ServerValue.TIMESTAMP});return id}
function txLog(updates,uid,id,data){updates[`transactions/${uid}/${id}`]={...data,reference:data.reference||id,createdAt:data.createdAt||now()}}
function notification(updates,uid,id,title,message,type='general'){updates[`user_notifications/${uid}/${id}`]={title,message,type,createdAt:now()}}

async function acquireLock(key,owner,ttl=30000){
  const r=db.ref(`locks/${key}`),t=now();const result=await r.transaction(cur=>{if(cur&&Number(cur.expiresAt)>t&&cur.owner!==owner)return;return{owner,expiresAt:t+ttl,createdAt:t}});if(!result.committed||result.snapshot.val()?.owner!==owner)throw new HttpsError('aborted','Another operation is in progress.');return()=>r.remove().catch(()=>{})
}
async function withLocks(keys,fn){const owner=crypto.randomUUID(),releases=[];try{for(const key of [...new Set(keys)].sort())releases.push(await acquireLock(key,owner));return await fn()}finally{for(const release of releases.reverse())await release()}}
async function markTasks(updates,uid,trigger,extra={}){const day=turkeyDay(),[defsSnap,progressSnap]=await Promise.all([db.ref('tasks/definitions').get(),db.ref(`user_tasks/${uid}/${day}`).get()]),defs=defsSnap.val()||{},progress=progressSnap.val()||{},t=now();for(const [id,task] of Object.entries(defs)){if(task.active!==false&&task.trigger===trigger){const current=progress[id]||{};updates[`user_tasks/${uid}/${day}/${id}`]={...current,completed:true,completedAt:current.completedAt||t,trigger,...extra}}}}
async function findUserUid(identifier){
  const raw=clean(identifier);if(!raw)return null;
  if((await db.ref(`users/${raw}`).get()).exists())return raw;
  const candidates=[`indexes/publicId/${keyify(raw)}`,`indexes/email/${keyify(raw)}`,`indexes/phone/${keyify(raw)}`,`referral_codes/${keyify(raw)}`];
  for(const p of candidates){const v=(await db.ref(p).get()).val();if(v)return typeof v==='string'?v:v.uid||null}
  return null
}
async function allocatePublicId(){const r=await db.ref('counters/publicId').transaction(v=>Math.max(100000,Number(v||100000))+1);return String(r.snapshot.val())}
async function reserveTicketNumber(drawKey,uid,ticketId){for(let i=0;i<40;i++){const n=String(crypto.randomInt(1000000,10000000));const r=await db.ref(`draw_ticket_numbers/${drawKey}/${n}`).transaction(cur=>cur||{uid,ticketId,reservedAt:now()});if(r.committed&&r.snapshot.val()?.ticketId===ticketId)return n}throw new HttpsError('resource-exhausted','Could not allocate a unique ticket number.')}
async function releaseTicketNumbers(drawKey,numbers){const u={};numbers.forEach(n=>u[`draw_ticket_numbers/${drawKey}/${n}`]=null);if(numbers.length)await db.ref().update(u)}
function debit(user,amount,useBonus,allowBonus){let real=round(user.realBalance),bonus=round(user.bonusBalance),remaining=round(amount),realUsed=0,bonusUsed=0;if(useBonus&&allowBonus){bonusUsed=Math.min(bonus,remaining);bonus=round(bonus-bonusUsed);remaining=round(remaining-bonusUsed)}if(remaining>real)throw new HttpsError('failed-precondition','Insufficient balance.');realUsed=remaining;real=round(real-realUsed);return{real,bonus,realUsed,bonusUsed}}
function weighted(segments){const list=segments.filter(x=>Number(x.weight||1)>0),total=list.reduce((a,x)=>a+Number(x.weight||1),0);let r=secureUnit()*total;for(let i=0;i<list.length;i++){r-=Number(list[i].weight||1);if(r<=0)return{segment:list[i],index:segments.indexOf(list[i])}}return{segment:list[list.length-1],index:segments.indexOf(list[list.length-1])}}

