  const existing=(await db.ref('admins').orderByChild('active').equalTo(true).limitToFirst(1).get()).val()||{};if(Object.keys(existing).length&&!req.auth.token?.admin)throw new HttpsError('failed-precondition','An administrator already exists. Ask an existing administrator to grant access.');
  const user=await auth.getUser(uid);await auth.setCustomUserClaims(uid,{...(user.customClaims||{}),admin:true,agent:false});await db.ref(`admins/${uid}`).set({email:user.email||'',active:true,createdAt:now()});await audit('bootstrap_admin',{uid,email:user.email||''});return{ok:true}
