    const [global,user,tickets]=await Promise.all([getVal('settings/global'),getVal(`users/${uid}`),getVal(`support/${uid}`)]);
    if(global?.supportEnabled===false)throw new HttpsError('failed-precondition','Support is disabled.');if(category==='agent_report'&&global?.agentReportsEnabled===false)throw new HttpsError('failed-precondition','Agent reports are disabled.');if(!user||user.status!=='active')throw new HttpsError('failed-precondition','Account is not active.');
